const body = $input.first().json.body || {};
const rawUrl = (body.url || '').trim();
if (!rawUrl) {
  throw new Error('Missing `url` in request body.');
}
const url = rawUrl.match(/^https?:\/\//i) ? rawUrl : 'https://' + rawUrl;
const focus = (body.focus || '').toString();

const response = await this.helpers.httpRequest({
  method: 'GET',
  url,
  followRedirect: true,
  returnFullResponse: false,
  ignoreHttpStatusErrors: true,
  headers: { 'User-Agent': 'Mozilla/5.0 (tbl4-classroom)' }
});

const raw = typeof response === 'string' ? response : JSON.stringify(response);
const stripped = raw
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const content = stripped.slice(0, 6000);

return [{ json: { url, focus, content } }];

